import javax.naming.Context;
import javax.naming.NamingEnumeration;
import javax.naming.directory.*;
import java.util.HashMap;
import java.util.Map;

public class LDAPUserSearcher {

    private static final String LDAP_URL = "ldap://ldap.example.com:389/";
    private static final String LDAP_USER = "ldapuser";
    private static final String LDAP_PASSWORD = "ldappassword";

    public Map<String, String> searchUserByUsername(String username) throws Exception {
        Context ctx = new InitialDirContext(new Hashtable<String, String>() {{
            put(Context.INITIAL_CONTEXT_FACTORY, "com.sun.jndi.ldap.LdapCtxFactory");
            put(Context.PROVIDER_URL, LDAP_URL);
            put(Context.SECURITY_PRINCIPAL, LDAP_USER);
            put(Context.SECURITY_CREDENTIALS, LDAP_PASSWORD);
        }});

        String ldapSearchFilter = "uid=" + username;
        SearchControls searchControls = new SearchControls(SearchControls.SUBTREE_SCOPE, ldapSearchFilter, new String[]{"mail", "displayName", "department"});
        NamingEnumeration<?> results = ctx.search("", ldapSearchFilter, searchControls);

        Map<String, String> userAttributes = new HashMap<>();
        while (results.hasMoreElements()) {
            SearchResult result = (SearchResult) results.next();
            Attributes attributes = result.getAttributes();

            userAttributes.put("email", attributes.get("mail").toString());
            userAttributes.put("fullName", attributes.get("displayName").toString());
            userAttributes.put("department", attributes.get("department").toString());
        }

        ctx.close();
        return userAttributes;
    }
}